#include<bits/stdc++.h>
using namespace std;
int ans[1010][1010];
char s[1010][1010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(ans,-1,sizeof(ans));
        int n,a,b;
        scanf("%d%d%d",&n,&b,&a);
        for(int i=1;i<=n;i++)
        {
            scanf("%s",s[i]+1);
        }
        int flag=0;
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                if(s[i][j]=='W')
                {
                    ans[i][j]=0;
                }
                if(s[i][j]=='B')
                {
                    ans[i][j]=1;
                    if(i<=a||j<=b||ans[i-a][j-b]==0)
                    {
                        flag=1;
                        break;
                    }
                    ans[i-a][j-b]=1;
                }
            }
            if(flag==1)
            {
                break;
            }
        }
        if(flag==1)
        {
            printf("-1\n");
            continue;
        }
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                if(s[i][j]=='G'&&ans[i][j]<0)
                {
                    if(i>a&&j>b&&ans[i-a][j-b]!=0)
                    {
                        ans[i][j]=0;
                        ans[i-a][j-b]=1;
                    }
                    else
                    {
                        ans[i][j]=1;
                    }
                }
            }
        }
        int s=0;
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                s+=ans[i][j];
            }
        }
        printf("%d\n",s);
    }
    return 0;
}
